import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';

const InfoDriverDetail = () => {
  const { truckId } = useParams();
  const [truck, setTruck] = useState(null);
  const [error, setError] = useState('');

  useEffect(() => {
    fetch(`http://localhost:5000/api/trucks/${truckId}`)
      .then(res => {
        if (!res.ok) throw new Error('Gagal mengambil data');
        return res.json();
      })
      .then(data => setTruck(data))
      .catch(err => setError(err.message));
  }, [truckId]);

  if (error) {
    return <p className="text-center text-red-500">{error}</p>;
  }

  if (!truck) {
    return <p className="text-center text-gray-500">Memuat data...</p>;
  }

  return (
    <div className="p-6">
      <Link to="/info-driver" className="text-blue-600 hover:underline mb-4 inline-block">← Kembali</Link>
      <div className="bg-white shadow-lg rounded-lg p-6">
        <img
          src={truck.image_path ? `http://localhost:5000/uploads/${truck.image_path}` : 'https://via.placeholder.com/300'}
          alt="Truck"
          className="w-full h-64 object-cover rounded mb-4"
        />
        <h2 className="text-2xl font-bold mb-2">Truck ID: {truck.truckId}</h2>
        <p><strong>Tipe:</strong> {truck.truckType}</p>
        <p><strong>Driver:</strong> {truck.driver}</p>
        <p><strong>Tanggal:</strong> {truck.date ? truck.date.split('T')[0] : ''}</p>
      </div>
    </div>
  );
};

export default InfoDriverDetail;
